create extension if not exists pgcrypto;
create type public.user_role as enum ('customer','vendor','crew','admin');
create type public.quote_status as enum ('new','reviewing','bidding','selected','in_progress','inspection','completed','cancelled');
create table public.profiles (id uuid primary key references auth.users(id) on delete cascade, role public.user_role not null default 'customer', full_name text, phone text, created_at timestamptz not null default now());
create table public.quote_requests (id uuid primary key default gen_random_uuid(), customer_id uuid references public.profiles(id), customer_name text not null, phone text not null, address text not null, project_type text not null, area_pyeong numeric, desired_date date, memo text, status public.quote_status not null default 'new', source text default 'website', created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create table public.quote_photos (id uuid primary key default gen_random_uuid(), quote_id uuid not null references public.quote_requests(id) on delete cascade, storage_path text not null, sort_order int not null default 0, created_at timestamptz not null default now());
create table public.vendors (id uuid primary key default gen_random_uuid(), owner_id uuid references public.profiles(id), company_name text not null, business_number text, verified boolean not null default false, insurance_verified boolean not null default false, service_regions text[] default '{}', created_at timestamptz not null default now());
create table public.bids (id uuid primary key default gen_random_uuid(), quote_id uuid not null references public.quote_requests(id) on delete cascade, vendor_id uuid not null references public.vendors(id), amount numeric not null check(amount>0), duration_days int, inclusions text, exclusions text, status text not null default 'submitted', created_at timestamptz not null default now(), unique(quote_id,vendor_id));
create table public.projects (id uuid primary key default gen_random_uuid(), quote_id uuid unique not null references public.quote_requests(id), selected_bid_id uuid references public.bids(id), start_date date, end_date date, contract_amount numeric, status public.quote_status not null default 'selected', created_at timestamptz not null default now());
create table public.project_evidence (id uuid primary key default gen_random_uuid(), project_id uuid not null references public.projects(id) on delete cascade, evidence_type text not null check(evidence_type in ('before','during','after','waste','document')), storage_path text not null, note text, created_at timestamptz not null default now());
create table public.settlements (id uuid primary key default gen_random_uuid(), project_id uuid unique not null references public.projects(id), gross_amount numeric not null, platform_fee numeric not null default 0, vendor_payout numeric generated always as (gross_amount-platform_fee) stored, status text not null default 'pending', approved_at timestamptz, paid_at timestamptz, created_at timestamptz not null default now());
alter table public.profiles enable row level security; alter table public.quote_requests enable row level security; alter table public.quote_photos enable row level security; alter table public.vendors enable row level security; alter table public.bids enable row level security; alter table public.projects enable row level security; alter table public.project_evidence enable row level security; alter table public.settlements enable row level security;
create policy "customer reads own quotes" on public.quote_requests for select using (customer_id=auth.uid());
create policy "customer creates own quotes" on public.quote_requests for insert with check (customer_id=auth.uid() or customer_id is null);
create policy "admin all quotes" on public.quote_requests for all using (exists(select 1 from public.profiles p where p.id=auth.uid() and p.role='admin')) with check (exists(select 1 from public.profiles p where p.id=auth.uid() and p.role='admin'));
-- Storage buckets: quote-photos/private, project-evidence/private. Signed URLs only.
